// 工作类型选项
export const JOB_TYPE_OPTIONS = [
  { value: 'full_time', label: '全职' },
  { value: 'part_time', label: '兼职' },
  { value: 'internship', label: '实习' },
  { value: 'freelance', label: '自由职业' }
]

// 求职状态选项
export const JOB_STATUS_OPTIONS = [
  { value: 'unemployed_looking', label: '离职-找工作' },
  { value: 'employed_not_looking', label: '在职-暂不考虑' },
  { value: 'employed_looking', label: '在职-看机会' },
  { value: 'student_internship', label: '在校-找实习' },
  { value: 'fresh_graduate', label: '应届生' }
]

// 薪资范围选项
export const SALARY_OPTIONS = [
  { value: '10K以下', label: '10K以下' },
  { value: '10K-15K', label: '10K-15K' },
  { value: '15K-20K', label: '15K-20K' },
  { value: '20K-25K', label: '20K-25K' },
  { value: '25K-30K', label: '25K-30K' },
  { value: '30K-40K', label: '30K-40K' },
  { value: '40K-50K', label: '40K-50K' },
  { value: '50K以上', label: '50K以上' }
]
